// transcode.c - مثال تحويل ترميز (transcoding) من FFmpeg
// يحوّل ملف من صيغة إلى أخرى (مثلاً من H.264 إلى H.265)

#include <libavcodec/avcodec.h>
#include <libavformat/avformat.h>

int main(int argc, char **argv) {
    AVFormatContext *input_ctx = NULL;
    AVFormatContext *output_ctx = NULL;
    const AVCodec *dec_codec, *enc_codec;
    AVCodecContext *dec_ctx, *enc_ctx;
    AVPacket *pkt = av_packet_alloc();
    AVFrame *frame = av_frame_alloc();
    AVFrame *enc_frame = av_frame_alloc();

    // 1. فتح المدخل وإعداد الـ decoder
    avformat_open_input(&input_ctx, argv[1], NULL, NULL);
    avformat_find_stream_info(input_ctx, NULL);
    int stream_idx = av_find_best_stream(input_ctx, AVMEDIA_TYPE_VIDEO, -1, -1, 0, NULL);
    dec_codec = avcodec_find_decoder(input_ctx->streams[stream_idx]->codecpar->codec_id);
    dec_ctx = avcodec_alloc_context3(dec_codec);
    avcodec_parameters_to_context(dec_ctx, input_ctx->streams[stream_idx]->codecpar);
    avcodec_open2(dec_ctx, dec_codec, NULL);

    // 2. إعداد الـ encoder وملف الخرج
    enc_codec = avcodec_find_encoder_by_name("libx265");
    enc_ctx = avcodec_alloc_context3(enc_codec);
    // نسخ المعاملات من الـ decoder مع تعديل ما يلزم
    avcodec_parameters_to_context(enc_ctx, input_ctx->streams[stream_idx]->codecpar);
    avformat_alloc_output_context2(&output_ctx, NULL, NULL, argv[2]);
    avcodec_open2(enc_ctx, enc_codec, NULL);

    // 3. حلقة التحويل: قراءة -> فك -> ترميز -> كتابة
    while (av_read_frame(input_ctx, pkt) >= 0) {
        if (pkt->stream_index == stream_idx) {
            avcodec_send_packet(dec_ctx, pkt);
            while (avcodec_receive_frame(dec_ctx, frame) >= 0) {
                // هنا: تحويل frame من decoder إلى encoder
                avcodec_send_frame(enc_ctx, frame);
                while (avcodec_receive_frame(enc_ctx, enc_frame) >= 0) {
                    // كتابة packet المشفّر إلى ملف الخرج
                    avcodec_receive_packet(enc_ctx, pkt);
                    pkt->stream_index = 0;
                    av_interleaved_write_frame(output_ctx, pkt);
                }
            }
        }
        av_packet_unref(pkt);
    }
    return 0;
}
